    114.99, 115.00, 48.00, 0.82, 'lb', '{"length": 12.5, "width": 5.0, "height": 5.5, "unit": "inch"}', 'White/White', 'M10', 'Full-Grain Leather', 'Unisex', '{"style": "low-top", "closure": "lace-up", "icon": true}',
